rule.query:
{
  "selection_img": {
    "Image|endswith": "/trufflehog"
  },
  "selection_cli_platform": {
    "CommandLine|contains": [
      " docker --image ",
      " Git ",
      " GitHub ",
      " Jira ",
      " Slack ",
      " Confluence ",
      " SharePoint ",
      " s3 ",
      " gcs "
    ]
  },
  "selection_cli_verified": {
    "CommandLine|contains": " --results=verified"
  },
  "condition": "selection_img or all of selection_cli_*"
}
